// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/health", wrapper.GetHealth)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/v1/auth/login", wrapper.Login)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/v1/auth/refresh", wrapper.RefreshToken)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/v1/auth/register", wrapper.Register)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/v1/authorizations", wrapper.ListAuthorizations)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/v1/authorizations/{id}/capture", wrapper.CaptureAuthorization)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/v1/cards", wrapper.ListCards)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/v1/cards", wrapper.IssueCard)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/v1/cards/{id}", wrapper.GetCard)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/v1/cards/{id}/authorize", wrapper.AuthorizeTransaction)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/v1/cards/{id}/freeze", wrapper.FreezeCard)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/v1/cards/{id}/unfreeze", wrapper.UnfreezeCard)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/v1/kyc", wrapper.SubmitKYC)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/v1/kyc/status", wrapper.GetKYCStatus)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/v1/notifications", wrapper.ListNotifications)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/v1/transfers", wrapper.ListTransfers)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/v1/transfers", wrapper.CreateTransfer)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/v1/wallet", wrapper.GetWalletBalance)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/v1/wallets", wrapper.ProvisionWallet)
	})

	return r
}

